    -- [13] Сад после похода (lord-of-the-rings)
    INSERT INTO stories (id, slug, title, status, author_id, ai_summary, created_at, updated_at) VALUES (
        'c9f914b9-109c-5b41-ba23-639fccd36de9', 'lotr-sad-posle-pohoda', 'Сад после похода', 'published', v_author_id, 'Война Кольца окончена. Сэм возвращается в разорённый Шир и берётся за самое мирное и самое важное дело своей жизни — заново вырастить то, что было вытоптано.',
        '2026-03-26T12:00:00+00:00', '2026-05-07T10:00:00+00:00');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('c9f914b9-109c-5b41-ba23-639fccd36de9', '10000001-0001-4001-8001-000000000003');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('c9f914b9-109c-5b41-ba23-639fccd36de9', '10000004-0004-4004-8004-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('c9f914b9-109c-5b41-ba23-639fccd36de9', '10000005-0005-4005-8005-000000000002');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('c9f914b9-109c-5b41-ba23-639fccd36de9', '10000006-0006-4006-8006-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('c9f914b9-109c-5b41-ba23-639fccd36de9', '10000002-0002-4002-8002-000000000004');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('c9f914b9-109c-5b41-ba23-639fccd36de9', '10000002-0002-4002-8002-000000000001');
    INSERT INTO chapters (id, story_id, title, content, draft_title, draft_content, status, created_at, updated_at) VALUES (
        '2282fe1d-5426-5732-8e3c-6cb81a79ff96', 'c9f914b9-109c-5b41-ba23-639fccd36de9', 'Пустые холмы', 'Сэм Скромби вернулся домой не таким, каким уходил. Он повидал Мордор и Гору Рока, выстоял там, где сломались бы и герои из старых песен, и принёс из похода то, чего не выразить словами. Но первое, что он почувствовал, ступив на родную землю Шира, было не облегчение. Это была боль.

Шир встретил его раной. Пока хоббиты сражались и страдали в дальних землях, здесь, дома, хозяйничали недобрые люди. Они вырубили деревья — старые, любимые, те, под которыми играли ещё деды нынешних хоббитов. Они снесли уютные норы и понастроили уродливых бараков. Они засыпали пруды, вытоптали сады, отравили самый воздух дымом своих мельниц. Зелёный, цветущий край, что снился Сэму все долгие месяцы похода, лежал перед ним голым и серым.

Хуже всего было Приречье. На месте знаменитого ряда раскидистых деревьев, что росли вдоль дороги сколько помнил себя Сэм, торчали пни. Просто пни. Их срубили без всякой нужды, из одной только злобы, — и эта бессмысленность ранила больнее всего. Сэм стоял среди пней и чувствовал, как к горлу подкатывает ком.

— Это можно отстроить, Сэм, — сказал ему Фродо, видя его горе. — Норы выкопаем заново, бараки снесём. Год-другой работы, и Шир будет как прежде.

— Норы — да, — тихо ответил Сэм. — А деревья, господин Фродо? Норы можно выкопать за лето. А такому дереву, чтоб стало большим да раскидистым, надо сто лет расти. Я-то этого уже не увижу. И дети мои не увидят. Вот что горше всего.

Фродо не нашёлся, что ответить, — да и что тут ответишь. Он положил руку другу на плечо, и они постояли молча среди пней, каждый со своей думой. Сэм глядел на срезы и считал кольца, а перед глазами вставали те деревья, какими он помнил их с детства: как шумели они листвой в летний полдень, как качались на ветвях качели, как водили под ними хороводы на праздник урожая. Всё это срубили за один день чужие злые руки. И от мысли, что вернуть утраченное скоро не выйдет при всём желании, у бывалого садовника по-настоящему щемило сердце.

Он опустился на корточки у одного из пней и провёл ладонью по срезу, считая годовые кольца. Их было много — дерево было старше его прадеда. Срубили за час то, что росло века. И в этом было что-то такое непоправимое, что Сэм, выстоявший в Мордоре, едва не заплакал здесь, среди мирных холмов родного Шира.

Но Сэм Скромби не был бы Сэмом Скромби, если бы умел подолгу предаваться унынию. Он был садовником — садовником в третьем поколении, и руки его знали землю лучше, чем голова знала слова. И где-то под горем, под комом в горле, уже зашевелилась другая, упрямая мысль. Может, он и не увидит новые деревья большими. Но это не повод их не сажать. Кто-то ведь посадил те, что срубили, — посадил, зная, что сам не отдохнёт в их тени. Так уж устроены сады. Их растят не для себя.

Сэм поднялся, отряхнул колени и в последний раз оглядел разорённое Приречье — уже иначе, не как горе, а как работу, которую предстоит сделать. Впереди была долгая весна. И у него, кажется, имелось кое-что, что могло превратить эту весну в чудо.',
        'Пустые холмы', 'Сэм Скромби вернулся домой не таким, каким уходил. Он повидал Мордор и Гору Рока, выстоял там, где сломались бы и герои из старых песен, и принёс из похода то, чего не выразить словами. Но первое, что он почувствовал, ступив на родную землю Шира, было не облегчение. Это была боль.

