    -- [20] Экзамен на стойкость (naruto)
    INSERT INTO stories (id, slug, title, status, author_id, ai_summary, created_at, updated_at) VALUES (
        '02addfa3-7940-5beb-bc25-1bb81fbcf8f8', 'naruto-ekzamen-na-stoykost', 'Экзамен на стойкость', 'published', v_author_id, 'На экзамене для будущих чунинов главное испытание оказывается не в силе техник, а в выборе: победить любой ценой — или остаться тем, кем хочешь быть.',
        '2026-03-12T12:00:00+00:00', '2026-04-30T08:00:00+00:00');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('02addfa3-7940-5beb-bc25-1bb81fbcf8f8', '10000001-0001-4001-8001-000000000004');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('02addfa3-7940-5beb-bc25-1bb81fbcf8f8', '10000004-0004-4004-8004-000000000002');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('02addfa3-7940-5beb-bc25-1bb81fbcf8f8', '10000005-0005-4005-8005-000000000003');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('02addfa3-7940-5beb-bc25-1bb81fbcf8f8', '10000006-0006-4006-8006-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('02addfa3-7940-5beb-bc25-1bb81fbcf8f8', '10000002-0002-4002-8002-000000000006');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('02addfa3-7940-5beb-bc25-1bb81fbcf8f8', '10000002-0002-4002-8002-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('02addfa3-7940-5beb-bc25-1bb81fbcf8f8', '10000003-0003-4003-8003-000000000002');
    INSERT INTO chapters (id, story_id, title, content, draft_title, draft_content, status, created_at, updated_at) VALUES (
        '036be5e8-4fe9-5a19-afd4-79963514f6c7', '02addfa3-7940-5beb-bc25-1bb81fbcf8f8', 'Лес испытаний', 'Экзамен на звание чунина славился своей жестокостью. Из множества генинов, что съезжались на него со всех окрестных деревень, повышение получали единицы. Остальные уходили ни с чем — а кое-кто и вовсе не уходил, потому что испытания были не понарошку.

Главным этапом был Лес — огромная, дикая чаща, куда экзаменуемых забрасывали с одним заданием: добыть особый свиток. Свитков было ровно вполовину меньше, чем участников. А это означало простую и жёсткую арифметику: чтобы пройти, ты должен был отнять свиток у другого. Экзамен нарочно сталкивал генинов лбами, проверяя не только силу, но и то, на что они готовы пойти ради победы.

Сора вошёл в Лес с твёрдым намерением пройти. Он был способным генином, упорно тренировался, и звание чунина значило для него очень много — это был шаг к мечте, к признанию, к тому, чтобы из мальчишки стать настоящим шиноби. Но был у Соры один принцип, который он усвоил от наставника и держал крепко: сила существует, чтобы защищать, а не чтобы отнимать. И этот принцип Лес испытаний собирался проверить на прочность.

Первые два дня прошли в выживании. Сора прятался, выслеживал, уходил от стычек, искал способ добыть свиток, не нападая на слабых. Это оказалось почти невозможно. Сильные команды охотились на одиночек. Хитрые расставляли ловушки. Лес быстро превращал вчерашних товарищей по академии в соперников, а кое-кого — и во врагов. Сора видел, как меняются лица знакомых ребят, как азарт и страх вытесняют в них всё человеческое, и ему делалось не по себе.

Лес работал именно так, как и был задуман, — он обнажал в людях то, что они прятали даже от себя. Под давлением голода, усталости и страха с генинов слетала всякая шелуха, и наружу проступала их истинная суть. Кто-то оказывался хитрее, кто-то — жёстче, чем можно было подумать в мирной академии. Сора с тревогой наблюдал эту перемену в знакомых лицах и всё чаще ловил себя на вопросе, которого прежде не задавал: а что Лес обнажит в нём самом? Устоит ли его принцип, когда дойдёт до дела, или тоже окажется шелухой, слетающей при первом серьёзном соблазне? Он не знал ответа. И это незнание тревожило его сильнее любого врага.

На третий день, измотанный и голодный, он всё ещё был без свитка. Время поджимало. Соблазн нарастал: вокруг то и дело попадались ослабевшие, раненые, отбившиеся генины — лёгкая добыча. Отними у такого свиток, и ты прошёл. Все так делали. Это было по правилам. Никто не осудил бы.

И вот наконец судьба подбросила ему такой случай. На лесной поляне Сора набрёл на генина из чужой деревни — раненого, обессиленного, лежащего без чувств у корней дерева. А рядом, выпавший из ослабевшей руки, лежал тот самый свиток. Бери — не хочу. Один шаг, и Сора пройдёт экзамен.

Он шагнул вперёд. И замер.',
        'Лес испытаний', 'Экзамен на звание чунина славился своей жестокостью. Из множества генинов, что съезжались на него со всех окрестных деревень, повышение получали единицы. Остальные уходили ни с чем — а кое-кто и вовсе не уходил, потому что испытания были не понарошку.

Главным этапом был Лес — огромная, дикая чаща, куда экзаменуемых забрасывали с одним заданием: добыть особый свиток. Свитков было ровно вполовину меньше, чем участников. А это означало простую и жёсткую арифметику: чтобы пройти, ты должен был отнять свиток у другого. Экзамен нарочно сталкивал генинов лбами, проверяя не только силу, но и то, на что они готовы пойти ради победы.

Сора вошёл в Лес с твёрдым намерением пройти. Он был способным генином, упорно тренировался, и звание чунина значило для него очень много — это был шаг к мечте, к признанию, к тому, чтобы из мальчишки стать настоящим шиноби. Но был у Соры один принцип, который он усвоил от наставника и держал крепко: сила существует, чтобы защищать, а не чтобы отнимать. И этот принцип Лес испытаний собирался проверить на прочность.

Первые два дня прошли в выживании. Сора прятался, выслеживал, уходил от стычек, искал способ добыть свиток, не нападая на слабых. Это оказалось почти невозможно. Сильные команды охотились на одиночек. Хитрые расставляли ловушки. Лес быстро превращал вчерашних товарищей по академии в соперников, а кое-кого — и во врагов. Сора видел, как меняются лица знакомых ребят, как азарт и страх вытесняют в них всё человеческое, и ему делалось не по себе.

Лес работал именно так, как и был задуман, — он обнажал в людях то, что они прятали даже от себя. Под давлением голода, усталости и страха с генинов слетала всякая шелуха, и наружу проступала их истинная суть. Кто-то оказывался хитрее, кто-то — жёстче, чем можно было подумать в мирной академии. Сора с тревогой наблюдал эту перемену в знакомых лицах и всё чаще ловил себя на вопросе, которого прежде не задавал: а что Лес обнажит в нём самом? Устоит ли его принцип, когда дойдёт до дела, или тоже окажется шелухой, слетающей при первом серьёзном соблазне? Он не знал ответа. И это незнание тревожило его сильнее любого врага.

На третий день, измотанный и голодный, он всё ещё был без свитка. Время поджимало. Соблазн нарастал: вокруг то и дело попадались ослабевшие, раненые, отбившиеся генины — лёгкая добыча. Отними у такого свиток, и ты прошёл. Все так делали. Это было по правилам. Никто не осудил бы.

И вот наконец судьба подбросила ему такой случай. На лесной поляне Сора набрёл на генина из чужой деревни — раненого, обессиленного, лежащего без чувств у корней дерева. А рядом, выпавший из ослабевшей руки, лежал тот самый свиток. Бери — не хочу. Один шаг, и Сора пройдёт экзамен.

Он шагнул вперёд. И замер.', 'published', '2026-03-12T12:00:00+00:00', '2026-03-12T13:00:00+00:00');
    INSERT INTO chapters (id, story_id, title, content, draft_title, draft_content, status, created_at, updated_at) VALUES (
        'a64576cb-7165-57a2-af1f-66b3dc20180f', '02addfa3-7940-5beb-bc25-1bb81fbcf8f8', 'Лёгкая добыча', 'Раненый генин был совсем плох. Бледный, в испарине, он метался в горячке, и Сора с одного взгляда понял: если оставить его так, без помощи, до конца экзамена парень не доживёт. Рана воспалилась, начинался жар, а сам он был без сознания и помочь себе не мог.

Свиток лежал рядом, в траве. Сора смотрел на него и чувствовал, как внутри борются двое. Один говорил голосом честолюбия: бери и уходи, это экзамен, тут каждый сам за себя, ты ничего ему не должен, он чужак, соперник, и оказался слаб — его беда. Возьми свиток и пройди. Ты столько шёл к этому.

Другой голос был тише, но Сора знал его лучше — это был голос наставника, голос его собственного сердца. Сила существует, чтобы защищать, а не чтобы отнимать. Что толку в звании чунина, добытом ценой брошенного умирать человека? Кем ты станешь, переступив через лежащего? Тем самым, в кого Лес превращает всех, — зверем, для которого чужая жизнь дешевле бумажки.

Сора стоял над свитком долго. А потом наклонился — но не за свитком. Он опустился на колени рядом с раненым, достал свои скудные припасы, чистую воду, бинты, которые берёг для себя, и принялся обрабатывать чужую рану. Промыл, перевязал, влил в пересохшие губы воды, остудил жар мокрой тканью. Он возился с врагом-соперником столько, сколько было нужно, забыв и про экзамен, и про время, и про свиток в траве.

Странное это было занятие — выхаживать того, кого по всем правилам полагалось ограбить. Сора и сам не до конца понимал, зачем тратит на чужака свои припасы, своё драгоценное время, свои силы, которых и так оставалось мало. Здравый смысл шиноби вопил, что это глупость, что так экзамен не сдают. Но руки делали своё дело помимо рассудка — промывали рану, меняли повязку, остужали жар, — потому что для Соры оставить человека умирать ради бумажки было попросту немыслимо. Не из расчёта. Не ради высокой цели. А просто потому, что иначе он не умел и не хотел уметь. И в этом, сам того не зная, он и проходил главное испытание Леса.

К ночи раненый пришёл в себя. Открыл мутные глаза, увидел склонившегося над ним Сору, увидел свой свиток, лежащий нетронутым рядом, — и не понял.

— Почему... ты не взял? — прохрипел он. — Свиток. Ты мог. Я был без сознания. Ты бы прошёл.

— Мог, — согласился Сора, поправляя повязку. — Но тогда я перестал бы быть тем, кем хочу быть. А звание чунина того не стоит. Лежи, не дёргайся, рану растревожишь.

Раненый смотрел на него так, будто Сора был самым непонятным существом на свете. В Лесу испытаний, где все грызли друг другу глотки за бумажку, кто-то выхаживал соперника, отказавшись от лёгкой победы. Это не укладывалось в голове.

— Ты дурак, — сказал он наконец, но без злости, скорее с изумлением. — Полный дурак. Из-за меня ты, скорее всего, провалишь экзамен.

— Может быть, — пожал плечами Сора. — Зато я по-прежнему я. Спи. Утром тебе станет легче.',
        'Лёгкая добыча', 'Раненый генин был совсем плох. Бледный, в испарине, он метался в горячке, и Сора с одного взгляда понял: если оставить его так, без помощи, до конца экзамена парень не доживёт. Рана воспалилась, начинался жар, а сам он был без сознания и помочь себе не мог.

