    -- [30] Дело о пустой квартире (sherlock)
    INSERT INTO stories (id, slug, title, status, author_id, ai_summary, created_at, updated_at) VALUES (
        '11acb9b6-0358-5b92-928a-7e30321c3c9d', 'sherlock-delo-o-pustoy-kvartire', 'Дело о пустой квартире', 'published', v_author_id, 'Консультирующий детектив Эшфорд берётся за дело об исчезновении человека из запертой изнутри квартиры. Разгадка окажется не в том, как он исчез, а в том, почему хотел исчезнуть.',
        '2026-02-20T12:00:00+00:00', '2026-04-20T08:00:00+00:00');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('11acb9b6-0358-5b92-928a-7e30321c3c9d', '10000001-0001-4001-8001-000000000007');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('11acb9b6-0358-5b92-928a-7e30321c3c9d', '10000004-0004-4004-8004-000000000002');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('11acb9b6-0358-5b92-928a-7e30321c3c9d', '10000005-0005-4005-8005-000000000003');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('11acb9b6-0358-5b92-928a-7e30321c3c9d', '10000006-0006-4006-8006-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('11acb9b6-0358-5b92-928a-7e30321c3c9d', '10000002-0002-4002-8002-000000000003');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('11acb9b6-0358-5b92-928a-7e30321c3c9d', '10000002-0002-4002-8002-000000000001');
    INSERT INTO chapters (id, story_id, title, content, draft_title, draft_content, status, created_at, updated_at) VALUES (
        '9bd31261-8dc2-50f2-9729-27b82e9a0ef6', '11acb9b6-0358-5b92-928a-7e30321c3c9d', 'Запертая изнутри', 'Туман в то утро лежал на улицах такой плотный, что газовые фонари казались жёлтыми пятнами, размытыми чьей-то небрежной кистью. Доктор Хейл поднялся по знакомой лестнице и застал своего друга, консультирующего детектива Эшфорда, за привычным занятием — тот сидел в кресле, сложив пальцы домиком, и смотрел в одну точку с видом человека, умирающего от скуки.

— Хейл, — произнёс он, не оборачиваясь, — вы пришли не просто навестить старого друга. На рукаве у вас типографская краска, какой пользуются в редакции «Вестника», а лицо выражает то особое возбуждение, какое бывает у вас, когда вы прочли что-нибудь загадочное. Итак, что пишут?

Доктор, давно переставший удивляться подобным фокусам, протянул газету.

Доктор Хейл давно свыкся с манерой друга огорошивать собеседника с порога, но всякий раз это маленькое представление вызывало у него тайное восхищение. Там, где другой увидел бы лишь усталого джентльмена с газетой, Эшфорд читал целую историю — по пятну на рукаве, по выражению лица, по сотне неуловимых мелочей. Это была не магия и не фокус, хотя выглядело именно так. Это был метод, доведённый до совершенства упорным трудом, и Хейл, врач по образованию, ценил его тем выше, что понимал: за внешней лёгкостью стоят годы дисциплины ума. Хейл и сам, прожив подле друга не один год, выучился замечать кое-что из того, мимо чего проходят прочие, — но до Эшфорда ему было по-прежнему так же далеко, как ученику до мастера, и доктор давно смирился с этой ролью, находя в ней своё скромное удовольствие.

— Исчезновение, — сказал он. — И, признаться, совершенно необъяснимое. Некий мистер Кроуфорд, банковский клерк, пропал из своей квартиры. Дверь была заперта изнутри на засов, окна закрыты на шпингалеты, единственный ключ найден внутри. И тем не менее человека в квартире нет. Будто растворился в воздухе.

Глаза Эшфорда впервые за утро ожили. Он выхватил газету, пробежал заметку глазами, и скука слетела с него, как сбрасывают надоевший плащ.

— Наконец-то, — пробормотал он. — Хоть что-то, не оскорбляющее интеллект. Запертая изнутри комната — это, Хейл, либо чушь для бульварных листков, либо прелестная задачка. Полиция, разумеется, в тупике?

— Инспектор Грегсон рвёт на себе волосы, — подтвердил доктор. — Он-то и просил вас взглянуть, хотя и сквозь зубы.

— Грегсон всегда просит сквозь зубы, а потом приписывает себе заслуги, — усмехнулся Эшфорд, вскакивая и хватая пальто. — Но дело того стоит. Едемте, друг мой. И прихватите ваш револьвер — не потому, что он понадобится, а потому, что с ним вы держитесь увереннее, а мне нужен уверенный спутник. Туман нам только на руку: в такую погоду люди забывают запирать рот так же тщательно, как двери.

Через четверть часа кэб уже вёз их сквозь молочную мглу к месту загадочного исчезновения, и Эшфорд, постукивая пальцами по колену, рассуждал вслух — не для Хейла, а для самого себя, как делал всегда, когда разум его разгонялся, нащупывая первые нити.',
        'Запертая изнутри', 'Туман в то утро лежал на улицах такой плотный, что газовые фонари казались жёлтыми пятнами, размытыми чьей-то небрежной кистью. Доктор Хейл поднялся по знакомой лестнице и застал своего друга, консультирующего детектива Эшфорда, за привычным занятием — тот сидел в кресле, сложив пальцы домиком, и смотрел в одну точку с видом человека, умирающего от скуки.

