    INSERT INTO story_tags (story_id, tag_id) VALUES ('30ce014f-65dd-5fc3-a726-e4ea686983ff', '10000002-0002-4002-8002-000000000006');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('30ce014f-65dd-5fc3-a726-e4ea686983ff', '10000002-0002-4002-8002-000000000001');
