    -- [38] Мейстер замёрзшего замка (game-of-thrones)
    INSERT INTO stories (id, slug, title, status, author_id, ai_summary, created_at, updated_at) VALUES (
        'aa16c84b-2922-59b9-9f06-ebf1b45dbec9', 'got-meyster-zamyorzshego-zamka', 'Мейстер замёрзшего замка', 'published', v_author_id, 'В забытом замке на самом краю Севера старый мейстер ведёт хроники, которые никто не читает. Когда к нему приходит беда, выясняется, что знания дороже мечей.',
        '2026-02-04T12:00:00+00:00', '2026-04-12T10:00:00+00:00');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('aa16c84b-2922-59b9-9f06-ebf1b45dbec9', '10000001-0001-4001-8001-000000000009');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('aa16c84b-2922-59b9-9f06-ebf1b45dbec9', '10000004-0004-4004-8004-000000000002');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('aa16c84b-2922-59b9-9f06-ebf1b45dbec9', '10000005-0005-4005-8005-000000000003');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('aa16c84b-2922-59b9-9f06-ebf1b45dbec9', '10000006-0006-4006-8006-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('aa16c84b-2922-59b9-9f06-ebf1b45dbec9', '10000002-0002-4002-8002-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('aa16c84b-2922-59b9-9f06-ebf1b45dbec9', '10000002-0002-4002-8002-000000000003');
    INSERT INTO chapters (id, story_id, title, content, draft_title, draft_content, status, created_at, updated_at) VALUES (
        '2943457c-3647-53a2-8a09-a3f63be6e2bf', 'aa16c84b-2922-59b9-9f06-ebf1b45dbec9', 'Хроники, которые никто не читает', 'Замок Зимний Дозор — не путать с великими твердынями Севера — стоял на самом краю обитаемых земель, там, где кончались дороги и начинались бескрайние снега. Это была маленькая, обветшалая крепость, гарнизон которой состоял из горстки немолодых воинов, а господа давно перебрались в места потеплее, наезжая сюда разве что раз в несколько лет.

Мейстер Виллем служил здесь уже сорок лет. Когда-то, молодым, он мечтал о большом замке, о знатных воспитанниках, о библиотеке, полной редких книг. Судьба распорядилась иначе — его направили на край света, в забытую всеми крепость, где не было ни знатных учеников, ни большой библиотеки, ни даже благодарных слушателей. Лишь снег, холод и тишина.

Но Виллем не озлобился. Он делал то, что велела ему цепь мейстера, — служил. Лечил обморожения и хвори немногочисленных обитателей замка. Следил за воронами. И, главное, вёл хроники. Каждый день, при свете чадящей свечи, он заносил в толстые книги всё, что видел и слышал: погоду, события в округе, рассказы редких путников, наблюдения за природой Севера, за повадками зверей, за тем, как меняется лёд на реке от года к году.

Никто не читал этих хроник. Господа не интересовались, в Цитадель за тридевять земель их отвезти было не с кем, а воины гарнизона едва знали грамоту. Виллем писал, в сущности, в пустоту — для самого себя да для тех неведомых потомков, что, быть может, когда-нибудь раскроют его книги. Иные на его месте давно бросили бы бесполезный труд. Но старый мейстер верил: знание, даже никем не читаемое, всё равно стоит того, чтобы его сохранить. Записанное не пропадает. Рано или поздно оно кому-нибудь да понадобится.

Особенно тщательно Виллем вёл записи о Севере — о том, чего не знали в тёплых землях. О том, как ведёт себя стужа, как читать небо перед большой бурей, какие травы спасают от лихорадки в краю, где не растёт ничего полезного, как выживать в снегах, когда припасы на исходе. За сорок лет он собрал бесценные сведения о суровом крае, в котором жил, — сведения, которых не было ни в одной книге Цитадели, потому что учёные мужи юга никогда не забирались так далеко на север.

Виллем не знал, что очень скоро именно эти его записи — никому не нужные хроники замёрзшего замка — окажутся единственным, что отделяет горстку людей от верной гибели. Что знание, которое он сорок лет собирал в пустоту, спасёт жизни, когда подведут и мечи, и стены. Пока же он просто макал перо в чернила, грел над свечой озябшие пальцы и писал — день за днём, год за годом, веря в свой тихий труд.',
        'Хроники, которые никто не читает', 'Замок Зимний Дозор — не путать с великими твердынями Севера — стоял на самом краю обитаемых земель, там, где кончались дороги и начинались бескрайние снега. Это была маленькая, обветшалая крепость, гарнизон которой состоял из горстки немолодых воинов, а господа давно перебрались в места потеплее, наезжая сюда разве что раз в несколько лет.

