    -- [42] За стеной (attack-on-titan)
    INSERT INTO stories (id, slug, title, status, author_id, ai_summary, created_at, updated_at) VALUES (
        'd168325d-f530-5472-a664-50fb71388c8e', 'aot-za-stenoy', 'За стеной', 'published', v_author_id, 'Юная новобранка разведотряда впервые выходит за стену — туда, где человечество не было сто лет. Она боится титанов, но больше всего боится того, что страх сделает с ней самой.',
        '2026-01-27T12:00:00+00:00', '2026-04-08T11:00:00+00:00');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('d168325d-f530-5472-a664-50fb71388c8e', '10000001-0001-4001-8001-00000000000a');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('d168325d-f530-5472-a664-50fb71388c8e', '10000004-0004-4004-8004-000000000002');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('d168325d-f530-5472-a664-50fb71388c8e', '10000005-0005-4005-8005-000000000003');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('d168325d-f530-5472-a664-50fb71388c8e', '10000006-0006-4006-8006-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('d168325d-f530-5472-a664-50fb71388c8e', '10000002-0002-4002-8002-000000000001');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('d168325d-f530-5472-a664-50fb71388c8e', '10000002-0002-4002-8002-000000000006');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('d168325d-f530-5472-a664-50fb71388c8e', '10000003-0003-4003-8003-000000000002');
    INSERT INTO chapters (id, story_id, title, content, draft_title, draft_content, status, created_at, updated_at) VALUES (
        '557d7a34-8301-5514-9fa5-865d22274450', 'd168325d-f530-5472-a664-50fb71388c8e', 'Ворота открываются', 'Майя стояла в строю на рассвете, у самых ворот, и слушала, как колотится её сердце. Сегодня разведотряд впервые за её службу выходил за стену — туда, в огромный, запретный мир, где сто лет хозяйничали титаны и куда человечество не смело ступать.

Ей было восемнадцать, и она сама не до конца понимала, зачем пошла в разведку. Можно было выбрать гарнизон — служить на стенах, в относительной безопасности. Можно было пойти в военную полицию, во внутренние земли, подальше от опасности. Но Майя выбрала разведку — отряд, из которого возвращался в лучшем случае каждый второй. Выбрала сама, против воли родных, против здравого смысла.

Почему? Она и сама толком не знала. Может быть, потому, что устала жить за стенами, как в клетке, не видя ничего, кроме одних и тех же улиц. Может быть, потому, что её брат когда-то ушёл за стену и не вернулся, и она хотела понять, ради чего. А может, просто потому, что не могла больше выносить мысль: всю жизнь прятаться и так и умереть, не увидев настоящего мира.

Командир отряда, суровая женщина с холодными глазами, прошла вдоль строя.

— Новобранцы, — сказала она ровно, без пафоса. — Сегодня многие из вас умрут. Это правда, и я не стану её прятать. Но запомните одно. Там, за стеной, ваш главный враг — не титан. Ваш главный враг — ваш собственный страх. Титан убивает тело. А страх убивает разум, и тогда вы делаете глупости и гибнете сами, да ещё тянете за собой других. Кто научится держать страх в узде — выживет. Кто нет — нет. Это всё. По коням.

Майя сглотнула. Слова командира врезались в неё. Она и вправду боялась — до дрожи в коленях, до тошноты. Боялась титанов, боялись смерти, но больше всего боялась опозориться, подвести, оказаться той, чей страх погубит товарищей.

Она и не подозревала, до чего обычен этот страх. Каждый в строю, даже бывалые на вид солдаты, чувствовал то же самое — комок в горле, холод в животе, предательскую дрожь в коленях. Просто все научились прятать его за каменными лицами, и оттого Майе казалось, будто боится она одна, будто все вокруг храбрее. Это и есть самая коварная ловушка страха: он убеждает тебя, что ты в нём одинок. Майя глубоко вдохнула холодный утренний воздух и попыталась убедить себя, что справится, — хотя сердце колотилось так, что, казалось, его слышит весь строй.

Заскрипели огромные ворота, медленно открываясь. За ними лежал он — мир за стеной, залитый утренним светом, бескрайний, прекрасный и смертельно опасный. Майя в последний раз глубоко вдохнула, сжала поводья и вместе с отрядом устремилась туда, куда сто лет не ступала нога человека. Навстречу своему страху.',
        'Ворота открываются', 'Майя стояла в строю на рассвете, у самых ворот, и слушала, как колотится её сердце. Сегодня разведотряд впервые за её службу выходил за стену — туда, в огромный, запретный мир, где сто лет хозяйничали титаны и куда человечество не смело ступать.

