    INSERT INTO chapters (id, story_id, title, content, draft_title, draft_content, status, created_at, updated_at) VALUES (
        'facf8e62-c85c-51ff-8983-b521571ae15d', 'c13d275c-11c7-50fb-b7d5-63960bd9eacc', 'Дальше, чем кто-либо', 'Год за годом карта Лотты росла, и человечество, шаг за шагом, узнавало мир, в котором жило вслепую целый век. Белые пятна отступали перед её пером. И настал день, когда Лотте выпало участвовать в самой дальней вылазке за всю историю разведки — экспедиции, что должна была дойти туда, где не бывал ещё никто.

Это был её звёздный час. Карта, которую она вела годами, делала эту экспедицию возможной: по ней проложили маршрут, рассчитали запасы воды, наметили укрытия. Без карты Лотты отряд не дошёл бы и до половины пути. Знание, копленное ценой стольких жизней, теперь вело живых дальше, чем когда-либо.

Они шли много дней, всё дальше за пределы изведанного. Лотта зарисовывала на ходу, лихорадочно, жадно — новые реки, новые леса, рельеф, какого не видел ни один человек за сто лет. Белые пятна на её карте таяли с каждым часом, заполняясь настоящим, живым миром.

И вот однажды на рассвете отряд поднялся на высокий хребет — и Лотта застыла с пером в руке. Перед ней, до самого горизонта, расстилалось то, чего не было ни на одной карте, чего не описывала ни одна легенда. Огромная долина, а за ней — очертания, которые Лотта поначалу приняла за горы. Но это были не горы. Это были стены. Другие стены, далёкие, незнакомые. А значит, за ними — другие люди. Человечество за стеной было не одно.

У Лотты задрожали руки. Это открытие переворачивало всё, что знал её народ о мире. Сто лет они считали себя последними людьми на земле, запертыми в кольце своих стен. А оказалось — есть и другие. Где-то там, за долиной, жили те, о ком никто и не подозревал.

Лотта склонилась над картой и дрожащей рукой нанесла на неё далёкие стены — самое важное, что она нарисовала за всю свою жизнь. Белое пятно, скрывавшее величайшую тайну мира, отступило перед её пером. И она знала: эта линия, как и все прежние, оплачена кровью тех, кто шёл сюда. Но эта линия меняла судьбу человечества.

Лотта стояла на хребте, не в силах оторвать глаз от далёких чужих стен, и чувствовала, как кружится голова от величия открывшегося. Всю жизнь её народ верил, что он один на свете, последний островок человечества в море титанов. Эта вера определяла всё — их страхи, их безнадёжность, их ощущение конца света. И вот одна линия, нанесённая её дрожащей рукой, разбивала эту веру вдребезги. Они были не одни. Где-то жили другие люди, со своей историей, своими стенами, своими тайнами. Мир оказался неизмеримо больше, чем думали за столетие заточения. И Лотта понимала, что держит в руках не просто карту — она держит ключ, способный изменить судьбу всех.

— Мы не одни, — прошептала она, глядя на далёкие стены. — Всё это время мы были не одни. Господи, сколько же ещё белых пятен впереди...

(продолжение следует)',
        'Дальше, чем кто-либо', 'Год за годом карта Лотты росла, и человечество, шаг за шагом, узнавало мир, в котором жило вслепую целый век. Белые пятна отступали перед её пером. И настал день, когда Лотте выпало участвовать в самой дальней вылазке за всю историю разведки — экспедиции, что должна была дойти туда, где не бывал ещё никто.

Это был её звёздный час. Карта, которую она вела годами, делала эту экспедицию возможной: по ней проложили маршрут, рассчитали запасы воды, наметили укрытия. Без карты Лотты отряд не дошёл бы и до половины пути. Знание, копленное ценой стольких жизней, теперь вело живых дальше, чем когда-либо.

Они шли много дней, всё дальше за пределы изведанного. Лотта зарисовывала на ходу, лихорадочно, жадно — новые реки, новые леса, рельеф, какого не видел ни один человек за сто лет. Белые пятна на её карте таяли с каждым часом, заполняясь настоящим, живым миром.

И вот однажды на рассвете отряд поднялся на высокий хребет — и Лотта застыла с пером в руке. Перед ней, до самого горизонта, расстилалось то, чего не было ни на одной карте, чего не описывала ни одна легенда. Огромная долина, а за ней — очертания, которые Лотта поначалу приняла за горы. Но это были не горы. Это были стены. Другие стены, далёкие, незнакомые. А значит, за ними — другие люди. Человечество за стеной было не одно.

У Лотты задрожали руки. Это открытие переворачивало всё, что знал её народ о мире. Сто лет они считали себя последними людьми на земле, запертыми в кольце своих стен. А оказалось — есть и другие. Где-то там, за долиной, жили те, о ком никто и не подозревал.

Лотта склонилась над картой и дрожащей рукой нанесла на неё далёкие стены — самое важное, что она нарисовала за всю свою жизнь. Белое пятно, скрывавшее величайшую тайну мира, отступило перед её пером. И она знала: эта линия, как и все прежние, оплачена кровью тех, кто шёл сюда. Но эта линия меняла судьбу человечества.

Лотта стояла на хребте, не в силах оторвать глаз от далёких чужих стен, и чувствовала, как кружится голова от величия открывшегося. Всю жизнь её народ верил, что он один на свете, последний островок человечества в море титанов. Эта вера определяла всё — их страхи, их безнадёжность, их ощущение конца света. И вот одна линия, нанесённая её дрожащей рукой, разбивала эту веру вдребезги. Они были не одни. Где-то жили другие люди, со своей историей, своими стенами, своими тайнами. Мир оказался неизмеримо больше, чем думали за столетие заточения. И Лотта понимала, что держит в руках не просто карту — она держит ключ, способный изменить судьбу всех.

— Мы не одни, — прошептала она, глядя на далёкие стены. — Всё это время мы были не одни. Господи, сколько же ещё белых пятен впереди...

(продолжение следует)', 'published', '2026-01-25T12:00:00+00:00', '2026-01-25T13:00:00+00:00');

    -- [45] Последний рубеж (attack-on-titan)
    INSERT INTO stories (id, slug, title, status, author_id, ai_summary, created_at, updated_at) VALUES (
        '2d7b74fc-1f19-5e22-a3da-980cfbc197b8', 'aot-posledniy-rubezh', 'Последний рубеж', 'published', v_author_id, 'Старый ветеран, потерявший на войне всё, готовит молодых новобранцев. Он суров и нелюдим — но за этой бронёй прячется человек, отчаянно не желающий, чтобы дети повторяли его судьбу.',
        '2026-01-21T12:00:00+00:00', '2026-04-05T08:00:00+00:00');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('2d7b74fc-1f19-5e22-a3da-980cfbc197b8', '10000001-0001-4001-8001-00000000000a');
    INSERT INTO story_tags (story_id, tag_id) VALUES ('2d7b74fc-1f19-5e22-a3da-980cfbc197b8', '10000004-0004-4004-8004-000000000002');
